import SwiftUI

struct ShareToNotesView: View {
    @State private var title = ""
    @State private var bodyText = ""

    private var fullText: String { title + "\n\n" + bodyText }

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            Text("Share to Notes to save into the Apple Notes app")
                .font(.caption)
                .foregroundStyle(.secondary)

            TextField("Title", text: $title)
                .textFieldStyle(.roundedBorder)
            TextEditor(text: $bodyText)
                .frame(minHeight: 80)
                .overlay(RoundedRectangle(cornerRadius: 8).stroke(Color.secondary.opacity(0.3), lineWidth: 1))

            ShareLink(item: fullText) {
                Label("Share to Notes", systemImage: "square.and.arrow.up")
            }
        }
        .padding()
    }
}
